(function () {
  const CONFIG = Object.assign({
    apiUrl: "http://localhost:8000",
    title: "Mynt",
    subtitle: "LIVE",
    greeting: "Got questions about the Plugin, Seed, or our pricing? \nI'm happy to help you!",
    logoUrl:"data:image/png;base64,",
  }, window.CW_CONFIG || {});

  const SESSION_KEY = "cw_session_id";
  const TYPING_SPEED_MS = 12;

  function getSessionId() {
    let id = localStorage.getItem(SESSION_KEY);
    if (!id) { id = crypto.randomUUID ? crypto.randomUUID() : String(Date.now()); localStorage.setItem(SESSION_KEY, id); }
    return id;
  }

  function el(tag, attrs, ...children) {
    const node = document.createElement(tag);
    Object.entries(attrs || {}).forEach(([k, v]) => { 
      if (k === "class") node.className = v; 
      else if (k.startsWith("on")) node.addEventListener(k.slice(2), v); 
      else node.setAttribute(k, v); 
    });
    children.forEach((c) => node.appendChild(typeof c === "string" ? document.createTextNode(c) : c));
    return node;
  }

  const getBotLogo = () => `<img src="${CONFIG.logoUrl}" alt="Bot" style="width: 100%; height: 100%; object-fit: contain; border-radius: 50%; padding: 12%; box-sizing: border-box;" />`;
  function build() {
    // 1. Circular Launcher & Tooltip
    const bubble = el("button", { id: "cw-bubble", "aria-label": "Open chat" },
      (() => { const d = el("div", { style: "width: 40px; height: 40px;" }); d.innerHTML = getBotLogo(); return d; })(),
      el("div", { class: "cw-tooltip" }, "👋 Hi, I'm Mynt,\nAsk me questions about Mintzy.")
    );

    // 2. Splash Screen Overlay
    const splash = el("div", { id: "cw-splash" }, 
      el("button", { id: "cw-splash-close", "aria-label": "Close" }, "\u2715"),
      el("div", { class: "cw-splash-content" }, 
        el("h1", {}, "Hello\nI'm Mynt"),
        (() => { const c = el("div", { class: "cw-avatar" }); c.innerHTML = getBotLogo(); return c; })(),
        el("h2", {}, "How can I help you?"), 
        el("button", { id: "cw-start-btn" }, "Ask right away")
      )
    );

    // 3. Native Welcome Header Inside Panel
    const welcomeBlock = el("div", { id: "cw-panel-welcome" },
      (() => { const c = el("div", { class: "cw-panel-avatar" }); c.innerHTML = getBotLogo(); return c; })(),
      el("h2", {}, "Hey There, I'm Mynt")
    );

    const msgs = el("div", { id: "cw-messages" });
    msgs.style.minHeight = "0";
    
    // Assemble Main Panel
    const panel = el("div", { id: "cw-panel" }, 
      splash, // Overlay placed on top
      el("div", { id: "cw-header" }, el("div", {}, el("div", { class: "cw-title" }, CONFIG.title), el("div", { class: "cw-subtitle" }, CONFIG.subtitle)), el("button", { id: "cw-close" }, "\u2715")),
      welcomeBlock,
      msgs,
      el("div", { id: "cw-inputbar" }, el("textarea", { id: "cw-input", rows: "1", placeholder: "Type a message..." }), el(
        "button", { id: "cw-send", "aria-label": "Send" },
        (() => {
          const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
          svg.setAttribute("viewBox", "0 0 24 24");
          const p = document.createElementNS("http://www.w3.org/2000/svg", "path");
          p.setAttribute("d", "M3 11l18-7-7 18-2.5-7L3 11z"); p.setAttribute("stroke", "#fff"); p.setAttribute("stroke-width", "1.8"); p.setAttribute("stroke-linejoin", "round"); p.setAttribute("fill", "none");
          svg.appendChild(p); return svg;
        })()
      ))
    );

    document.body.appendChild(bubble); document.body.appendChild(panel);
    return { bubble, panel, splash, welcomeBlock, startBtn: panel.querySelector("#cw-start-btn"), splashClose: panel.querySelector("#cw-splash-close"), messages: msgs, input: panel.querySelector("#cw-input"), send: panel.querySelector("#cw-send"), close: panel.querySelector("#cw-close") };
  }

  function addMessage(container, text, role) {
    if (role === "bot") {
      const row = el("div", { class: "cw-bot-row" });
      const avatar = el("div", { class: "cw-bot-avatar" });
      avatar.innerHTML = getBotLogo();
      row.appendChild(avatar);
      
      const msg = el("div", { class: "cw-msg cw-bot" });
      msg.innerHTML = window.marked ? window.marked.parse(text) : text;
      row.appendChild(msg); container.appendChild(row);
    } else {
      const msg = el("div", { class: "cw-msg cw-user" });
      msg.textContent = text; container.appendChild(msg);
    }
    container.scrollTop = container.scrollHeight;
  }

  function addTyping(container) {
    const row = el("div", { class: "cw-bot-row" });
    const avatar = el("div", { class: "cw-bot-avatar" });
    avatar.innerHTML = getBotLogo();
    row.appendChild(avatar);

    const typing = el("div", { class: "cw-msg cw-typing" }, el("span", { class: "cw-dot" }), el("span", { class: "cw-dot" }), el("span", { class: "cw-dot" }));
    row.appendChild(typing); container.appendChild(row); container.scrollTop = container.scrollHeight;
    return row;
  }

  function typeMessage(container, text) {
    const row = el("div", { class: "cw-bot-row" });
    const avatar = el("div", { class: "cw-bot-avatar" });
    avatar.innerHTML = getBotLogo();
    row.appendChild(avatar);

    const msg = el("div", { class: "cw-msg cw-bot" });
    row.appendChild(msg); container.appendChild(row);

    const words = text.split(/(\s+)/); let i = 0;
    return new Promise((resolve) => {
      function step() {
        i++; const partial = words.slice(0, i).join("");
        msg.innerHTML = window.marked ? window.marked.parse(partial) : partial;
        container.scrollTop = container.scrollHeight;
        if (i < words.length) setTimeout(step, TYPING_SPEED_MS); else resolve(msg);
      }
      step();
    });
  }

  async function sendMessage(ui, text) {
    // Hide the native header on first message
    if (ui.welcomeBlock && !ui.welcomeBlock.classList.contains("cw-hidden-header")) {
      ui.welcomeBlock.classList.add("cw-hidden-header");
    }

    addMessage(ui.messages, text, "user");
    ui.input.value = ""; ui.send.disabled = true;
    const typing = addTyping(ui.messages);

    try {
      const res = await fetch(`${CONFIG.apiUrl}/chat`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ session_id: getSessionId(), message: text }) });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      typing.remove(); await typeMessage(ui.messages, data.reply);
    } catch (err) {
      typing.remove(); addMessage(ui.messages, "I couldn't reach the server just now. Please try again in a moment.", "bot");
    } finally { ui.send.disabled = false; }
  }


  // Avoid overlapping with Cookie Consent banner
  function adjustPositionForCookieBanner() {
    const consent = localStorage.getItem("mintzy-cookie-consent");
    const hasBanner = document.getElementById("mintzy-cookie-banner") !== null;
    const bubble = document.getElementById("cw-bubble");
    const panel = document.getElementById("cw-panel");
    if (consent === null && hasBanner) {
      if (bubble) bubble.style.setProperty("bottom", "96px", "important");
      if (panel) panel.style.setProperty("bottom", "160px", "important");
    } else {
      if (bubble) bubble.style.setProperty("bottom", "24px", "important");
      if (panel) panel.style.setProperty("bottom", "90px", "important");
    }
  }

  document.addEventListener("click", (e) => {
    if (e.target && e.target.closest && e.target.closest("button") && 
        (e.target.textContent.includes("Accept") || e.target.textContent.includes("Decline"))) {
      setTimeout(adjustPositionForCookieBanner, 200);
    }
  });

  function init() {
    const ui = build();
    adjustPositionForCookieBanner(); let opened = false;
    ui.bubble.addEventListener("click", () => ui.panel.classList.add("cw-open"));
    ui.close.addEventListener("click", () => ui.panel.classList.remove("cw-open"));
    ui.splashClose.addEventListener("click", () => ui.panel.classList.remove("cw-open"));
    
    ui.startBtn.addEventListener("click", () => { 
      ui.splash.classList.add("cw-hidden"); 
      if (!opened) { addMessage(ui.messages, CONFIG.greeting, "bot"); opened = true; } 
      setTimeout(() => ui.input.focus(), 300);
    });

    ui.send.addEventListener("click", () => { const text = ui.input.value.trim(); if (text) sendMessage(ui, text); });
    ui.input.addEventListener("keydown", (e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); const text = ui.input.value.trim(); if (text) sendMessage(ui, text); } });
    ui.input.addEventListener("input", () => { ui.input.style.height = "auto"; ui.input.style.height = Math.min(ui.input.scrollHeight, 90) + "px"; });
  }

  if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", init); else init();
})();